{
  "verses": [
    {
      "n": 25,
      "column": "left",
      "text": "Woj tad ta Drandse pahr\nwinnu Dsibres turrehs? jsdal-\nlis tee winnu starp teem Prez-\nzinekeem?\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Marri tu ar Dsenmukeem\nwinna Ahdu pischt / jeb ar\nScheberkti winna Galiwu.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Rad tu tawu Rohku us\nwinnu leezi/ tad peeminni tah-\ndu Karzu effam / ko tu ne pa-\nspehsi.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Redsi / winna Zerriba jahs Lahpas/ deggofchas Dsu\nbuhs weltiga / neggi tas/ kad steles no tahs islezz.\nwinsch to eeranga weegli ais-\nscreeu?\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "Ne weens irr tik drohsch/\nkas winnu drihktetu iszelt/ kas\ntad buhtu/ kas manna Preekscha\nwarretu pastahweht.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Kas irr man ko lab pa-\npreeksch darrijs/ ka man bij tam\nto atmakfaht ? kas appakich wis-\nfahm Debbefim irr/ tas peederr\nman.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Man arri kluftu ne jazeefch\nno winnu Lohzekteem / Stipru-\nma/ un no winna skaista Gihuna.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Kuefch drihktetu winna\nDrebbi atklaht? kas warr ar ta-\nweim Lauschueem pee winna\nklaht eet?\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Kas warr winna Waiga\nSchoklus atplehst ? apkahrt\nwinna Sohbeem irr Jstruhzt-\nnafhana.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Winna levni {Swihat\nka} stipras preekschturranias\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Ween irr tik tuwn pee\ntreem/ ka Wehjsch starp teem\nwarr nahkt.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Tee peelihp zitti pee\nteen/ un fatturrahs/ ka tee\nschkirrahs.\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Winna Schkaudifcha\nspihd ka Gaischums/ un win-\nAzzis irr fa ta Ausfcta Az-\nWahki.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "No winna Muttescha\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "No winna Nahsim is\nDuhmi/ittin ka no wehrdosche\nPohdeem/ un karsteem Katlee\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Winna Dwajcha war\ntu Ohgles eededsinaht/ un Le\nmas iseet no winna Muttes.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Winna Kattis paleek\nti stiprs / un kad winsch far\nPreekscha apbehdina/ tas\n(winnam) Preeks.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Winna Meefas Lohze\nkerrahs kohpa/ tee turrahs ze\nkohpa/ ka ne warr kustinaht.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Winna Girds irr zee\nitt ka Akmins / un ka wee\nGabbals no appakscheja Dsirn\nAkmina.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Rad winsch zelfahs/ t\nbihstahs tee Stipree / ka tee\ntohp falansiti/ tad tee (no Gre-\nkeem) schkistahs.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Rad kas ar Sobbi\nwinnu aiskarr/ tad tas ne p\nstahwehs/ ueds arri Schkeb\nne\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
